    /// <summary>
    /// Finds the ETGSPAINSalesPackingSlipImport record by its RecId.
    /// </summary>
    /// <param name="_recId">The RecId of the ETGSPAINSalesPackingSlipImport record.</param>
    /// <param name="_update">Optional: Whether to lock the record for update.</param>
    /// <returns>Returns the ETGSPAINSalesPackingSlipImport record, or null if not found.</returns>
    static ETGSPAINSalesPackingSlipImport findRecId(RecId       _recId,
                               boolean     _update = false)
    {
        ETGSPAINSalesPackingSlipImport ETGSPAINSalesPackingSlipImport;

        if (_recId)
        {
            if (_update)
            {
                ETGSPAINSalesPackingSlipImport.selectForUpdate(_update);
            }

            select ETGSPAINSalesPackingSlipImport
                where ETGSPAINSalesPackingSlipImport.RecId == _recId;
        }

        return ETGSPAINSalesPackingSlipImport;
    }

/// <summary>
/// Modifies field values in the ETGSPAINSalesPackingSlipImport record.
/// </summary>
/// <param name="_fieldName">The name of the field being modified.</param>
/// <param name="_arrayIndex">Optional: The index of the field in an array (if applicable).</param>
public void modifiedFieldValue(FieldName _fieldName, int _arrayIndex = 1)
{
    super(_fieldName, _arrayIndex);

    switch (_fieldName)
    {
        case fieldStr(ETGSPAINSalesPackingSlipImport, InventLocationId):
            SalesLine salesLine = SalesLine::findRecId(this.SalesLineRefRecId, true);
            InventDim inventDim = salesLine.inventDim();

            if (inventDim.InventLocationId != this.InventLocationId)
            {
                inventDim.InventLocationId = this.InventLocationId;
                inventDim = InventDim::findOrCreate(inventDim);

                ttsbegin;
                salesLine.InventDimId = inventDim.inventDimId;
                salesLine.update();
                ttscommit;
            }
            break;
        default:
            break;
    }
}
